mapper.delete:

delete
  from swm_employee_monthly_bak
 where income_period = #{incomePeriod, jdbcType = VARCHAR}

mapper.select:

select case when exists (select 1 from swm_employee_monthly_bak semb where convert(varchar(7),semb.bak_date,20) =
    convert(varchar(7),getdate(),20)
 ) then 1 else 0 end
